const actions = {
  getBugData({ commit }) {
    $axios.get("/devops/f11/s1/top/bug").then((res) => {
      commit("UPDATE_BUGDATA", res.body || []);
    });
  },
  getTaskData({ commit, state }) {
    $axios.get("/devops/f11/s1/task").then((res) => {
      let num = 0;
      if (res.body && res.body.length) {
        res.body.map((item) => {
          num += item.total;
        });
      }
      commit("UPDATE_TASKDATA", {
        list: res.body,
        num: num,
      });
    });
  },
  getWorkData({ commit }) {
    $axios.get("/devops/f11/s1/top/workload").then((res) => {
      commit("UPDATE_WORKDATA", res.body || []);
    });
  },
  getStaffData({ commit }) {
    $axios.get("/devops/f11/s1/team").then((res) => {
      let num = 0;
      let obj = {};
      if (res.body.teamGroup && res.body.teamGroup.length) {
        res.body.teamGroup.map((item) => {
          num += item.num;
          obj[item.label] = item;
        });
      }
      res.body.teamGroup = obj;
      if (res.body) {
        commit("UPDATE_STAFFDATA", {
          list: res.body,
          num: num,
        });
      }
    });
  },
  showMessage(err) {
    console.log(3);
  },
};
const getters = {
  gettersTaskInfo(state, data) {
    return state.taskData || [];
  },
  gettersWorkData(state, data) {
    return state.workData || [];
  },
  gettersBugData(state, data) {
    return state.bugData || [];
  },
  gettersTaskNum(state, data) {
    return state.allTask || [];
  },
  gettersStaffData(state, data) {
    return state.staffData || {};
  },
  gettersTotalStaff() {
    return state.allStaff;
  },
  gettersBugMonth(state, data) {
    return state._BUG;
  },
};
const mutations = {
  UPDATE_BUGDATA(state, data) {
    state.bugData = [...data];
  },
  UPDATE_TASKDATA(state, data) {
    const { list, num } = data;
    state.taskData = [...list];
    state.allTask = num;
  },
  UPDATE_WORKDATA(state, data) {
    state.workData = [...data];
  },
  UPDATE_STAFFDATA(state, data) {
    state.staffData = { ...data.list };
    state.allStaff = data.num;
  },
};
const store = new Vuex.Store({
  state,
  actions,
  getters,
  mutations,
});
export default store;
