import axios from 'axios'
import store from './store/index'
import $config from "./config.js";
// 线上环境配置axios.defaults.baseURL，生产环境则用proxy代理
axios.defaults.baseURL = $config.baseURL;
axios.defaults.timeout = 30000; // 超时时间


//请求拦截器
axios.interceptors.request.use(config => {
  config.headers.Authorization = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJzY29wZSI6WyJzZXJ2ZXIiXSwianRpIjoiODg1NDk5YjEtMmI0Mi00OTFhLWE2YmMtYWJmNTBjYWJhNzhhIiwiY2xpZW50X2lkIjoiQ1JNX1NDUkVFTiJ9.uhBT3-brs4CJ6vwG44Hd0UJZ5AWHOlpdxdfYlHtjKLY';
  config.headers['Access-Control-Allow-Origin'] = '*';
  return config
}, error => {
  return Promise.reject(error)
})
//响应拦截器即异常处理
axios.interceptors.response.use(response => {
  if (response.data.status) {
    return Promise.resolve(response.data)
  } else {
    store.dispatch('showMessage', {
      type: 'error',
      message: response.data.message || response.data.msg || response.data.errMsg
    })
    return Promise.reject(response.data.message || response.data.msg || response.data.errMsg, response)
  }

}, err => {
  if (err && err.response) {
    switch (err.response.status) {
      case 400:
        err.message = '错误请求'
        break;
      case 401:
        err.message = '未授权，请重新登录'
        break;
      case 403:
        err.message = '没有访问权限，拒绝访问'
        break;
      case 404:
        err.message = '请求错误,未找到该资源'
        break;
      case 405:
        err.message = '请求方法未允许'
        break;
      case 500:
        err.message = err.response.data.message || '服务器端出错';
        break;
      default:
        err.message = `连接错误${err.response.msg}`
    }
  } else {
    err.message = "连接到服务器失败"
  }
  if (err.response.status !== 401) {
    store.dispatch('showMessage', {
      type: 'error',
      message: err.message || err.response.msg
    })
  }
  return Promise.reject(err.response, err)
})

export default {
  //get请求
  get(url, param, header) {

    return axios({
      method: 'get',
      url,
      headers: {
        ...(header || {})
      },
      params: param || {}
    })
  },
  //post请求
  post(url, param, header) {
    return axios({
      method: 'post',
      url,
      headers: {
        ...(header || {}),
        'Content-Type': 'application/json;charse=UTF-8'
      },
      data: param || {}
    })
  },
  //post请求
  put(url, param, header) {
    return axios({
      method: 'put',
      url,
      headers: {
        ...(header || {}),
        'Content-Type': 'application/json;charse=UTF-8'
      },
      data: param || {}
    })
  },
  // delete
  delete(url, param, header) {
    return axios({
      method: 'delete',
      url,
      headers: {
        ...(header || {})
      },
      params: param || {},

    })
  }
}