import Vue from 'vue'
import Router from 'vue-router'

Vue.use(Router)

export default new Router({
  // mode: 'hash',
  routes: [{
    path: '/',
    name: 'StaffShow',
    component: () =>
      import('../views/staff-show'),
    meta: {
      title: '员工展示'
    }
  },{
    path: '/teamShow',
    name: 'TeamShow',
    component: () =>
      import('../views/team-show'),
    meta: {
      title: '项目监控'
    }
  }]
})